import{_ as e,o,c as i,ag as r}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"Personalización y Archivos","description":"","frontmatter":{},"headers":[],"relativePath":"maxstaff/adicional/personalización.md","filePath":"maxstaff/adicional/personalización.md"}'),l={name:"maxstaff/adicional/personalización.md"};function c(s,a,d,n,t,m){return o(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="personalizacion-y-archivos" tabindex="-1">Personalización y Archivos <a class="header-anchor" href="#personalizacion-y-archivos" aria-label="Permalink to &quot;Personalización y Archivos&quot;">​</a></h1><blockquote><p>MaxStaff es 100% configurable. Puedes modificar cada mensaje, menú, color y prefijo del plugin para adaptarlo a la temática de tu servidor.</p></blockquote><h2 id="_1-cambiar-el-idioma" tabindex="-1">1. Cambiar el Idioma <a class="header-anchor" href="#_1-cambiar-el-idioma" aria-label="Permalink to &quot;1. Cambiar el Idioma&quot;">​</a></h2><p>El plugin viene con traducciones oficiales integradas. Para cambiar el idioma base:</p><ol><li>Ve a <code>plugins/MaxStaff/config.yml</code>.</li><li>Busca la opción <code>language:</code> dentro de la sección general.</li><li>Cambia <code>&quot;en&quot;</code> por <code>&quot;es&quot;</code> para español (o viceversa).</li><li>Usa <code>/maxstaff reload</code> en el servidor. El archivo <code>messages_es.yml</code> se generará automáticamente en la carpeta <code>lang/</code>.</li></ol><h2 id="_2-codigos-de-color-y-formato" tabindex="-1">2. Códigos de Color y Formato <a class="header-anchor" href="#_2-codigos-de-color-y-formato" aria-label="Permalink to &quot;2. Códigos de Color y Formato&quot;">​</a></h2><p>Todos los archivos del plugin soportan los códigos de color tradicionales de Minecraft usando el símbolo <code>&amp;</code> (ej. <code>&amp;a</code> para verde, <code>&amp;c</code> para rojo).</p><p>Además, si tu servidor está en una versión que soporta colores hexadecimales (1.16+), puedes usarlos en cualquier mensaje o menú usando el formato tradicional de Spigot.</p><h2 id="_3-desactivar-modulos-comandos" tabindex="-1">3. Desactivar Módulos (Comandos) <a class="header-anchor" href="#_3-desactivar-modulos-comandos" aria-label="Permalink to &quot;3. Desactivar Módulos (Comandos)&quot;">​</a></h2><p>Si ya utilizas otro plugin para un comando específico (por ejemplo, si prefieres usar el <code>/vanish</code> de Essentials en lugar del de MaxStaff), puedes desactivar el comando de MaxStaff directamente desde el <code>config.yml</code>.</p><ul><li>Busca la sección de comandos en la configuración y ponlos en <code>false</code>.</li><li>Al hacerlo, si alguien intenta usar ese comando de MaxStaff, el plugin liberará el comando para que lo tome tu otro plugin sin generar conflictos.</li></ul>',11)])])}const f=e(l,[["render",c]]);export{u as __pageData,f as default};
